import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import akka.http.scaladsl.unmarshalling.Unmarshaller

import scala.xml._
import scala.collection.mutable
import scala.concurrent.{ExecutionContextExecutor, Future}
import scala.util.{Failure, Success, Try}

case class ConfigSetting(key: String, value: String, attributes: Map[String, String] = Map.empty)
case class ConfigParseResult(settings: List[ConfigSetting], errors: List[String])

object ConfigXmlParser {

  def parseConfigXml(xmlString: String): ConfigParseResult = {
    try {
      val xml = XML.loadString(xmlString)
      val settings = extractSettings(xml)
      ConfigParseResult(settings, List.empty)
    } catch {
      case e: org.xml.sax.SAXParseException =>
        ConfigParseResult(List.empty, List(s"XML Parse Error: ${e.getMessage}"))
      case e: Exception =>
        ConfigParseResult(List.empty, List(s"Error: ${e.getMessage}"))
    }
  }

  private def extractSettings(node: Node, prefix: String = ""): List[ConfigSetting] = {
    node match {
      case elem: Elem =>
        val currentPath = if (prefix.isEmpty) elem.label else s"$prefix.${elem.label}"
        val attributes = elem.attributes.asAttrMap

        val childElements = elem.child.collect { case e: Elem => e }

        if (childElements.isEmpty) {
          val textValue = elem.text.trim
          if (textValue.nonEmpty || attributes.nonEmpty) {
            List(ConfigSetting(currentPath, textValue, attributes))
          } else {
            List.empty
          }
        } else {
          val selfSetting = if (attributes.nonEmpty) {
            List(ConfigSetting(currentPath, "", attributes))
          } else {
            List.empty
          }
          selfSetting ++ childElements.flatMap(child => extractSettings(child, currentPath)).toList
        }

      case _ => List.empty
    }
  }

  def extractSettingByKey(xmlString: String, key: String): Option[ConfigSetting] = {
    val result = parseConfigXml(xmlString)
    result.settings.find(_.key == key)
  }

  def extractSettingsByPrefix(xmlString: String, prefix: String): List[ConfigSetting] = {
    val result = parseConfigXml(xmlString)
    result.settings.filter(_.key.startsWith(prefix))
  }

  def toFlatMap(xmlString: String): Map[String, String] = {
    val result = parseConfigXml(xmlString)
    result.settings.map(s => s.key -> s.value).toMap
  }
}

object ConfigToJson {
  def settingToJson(setting: ConfigSetting): String = {
    val attrsJson = if (setting.attributes.nonEmpty) {
      val attrs = setting.attributes.map { case (k, v) =>
        s""""$k":"${escapeJson(v)}""""
      }.mkString(",")
      s""","attributes":{$attrs}"""
    } else ""

    s"""{"key":"${escapeJson(setting.key)}","value":"${escapeJson(setting.value)}"$attrsJson}"""
  }

  def resultToJson(result: ConfigParseResult): String = {
    val settingsJson = result.settings.map(settingToJson).mkString(",")
    val errorsJson = result.errors.map(e => s""""${escapeJson(e)}"""").mkString(",")
    s"""{"settings":[$settingsJson],"errors":[$errorsJson]}"""
  }

  private def escapeJson(s: String): String = {
    s.replace("\\", "\\\\")
      .replace("\"", "\\\"")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
  }
}

object ConfigManagementService extends App {

  implicit val system: ActorSystem = ActorSystem("config-management")
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  implicit val xmlUnmarshaller: Unmarshaller[HttpEntity, String] =
    Unmarshaller.stringUnmarshaller

  val configStore: mutable.Map[String, String] = mutable.Map.empty

  val route: Route =
    pathPrefix("api" / "config") {
      concat(
        path("parse") {
          post {
            entity(as[String]) { xmlBody =>
              val result = ConfigXmlParser.parseConfigXml(xmlBody)
              val json = ConfigToJson.resultToJson(result)
              complete(HttpEntity(ContentTypes.`application/json`, json))
            }
          }
        },
        path("parse" / "flat") {
          post {
            entity(as[String]) { xmlBody =>
              Try(ConfigXmlParser.toFlatMap(xmlBody)) match {
                case Success(flatMap) =>
                  val json = flatMap.map { case (k, v) =>
                    s""""${k}":"${v}""""
                  }.mkString("{", ",", "}")
                  complete(HttpEntity(ContentTypes.`application/json`, json))
                case Failure(e) =>
                  complete(StatusCodes.BadRequest,
                    HttpEntity(ContentTypes.`application/json`,
                      s"""{"error":"${e.getMessage}"}"""))
              }
            }
          }
        },
        path("setting" / Segment) { key =>
          post {
            entity(as[String]) { xmlBody =>
              ConfigXmlParser.extractSettingByKey(xmlBody, key) match {
                case Some(setting) =>
                  complete(HttpEntity(ContentTypes.`application/json`,
                    ConfigToJson.settingToJson(setting)))
                case None =>
                  complete(StatusCodes.NotFound,
                    HttpEntity(ContentTypes.`application/json`,
                      s"""{"error":"Setting not found for key: $key"}"""))
              }
            }
          }
        },
        path("settings" / "prefix" / Segment) { prefix =>
          post {
            entity(as[String]) { xmlBody =>
              val settings = ConfigXmlParser.extractSettingsByPrefix(xmlBody, prefix)
              val json = settings.map(ConfigToJson.settingToJson).mkString("[", ",", "]")
              complete(HttpEntity(ContentTypes.`application/json`, json))
            }
          }
        },
        path("store" / Segment) { configName =>
          concat(
            put {
              entity(as[String]) { xmlBody =>
                // Validate XML before storing
                val result = ConfigXmlParser.parseConfigXml(xmlBody)
                if (result.errors.isEmpty) {
                  configStore(configName) = xmlBody
                  complete(HttpEntity(ContentTypes.`application/json`,
                    s"""{"status":"stored","name":"$configName","settingsCount":${result.settings.size}}"""))
                } else {
                  complete(StatusCodes.BadRequest,
                    HttpEntity(ContentTypes.`application/json`,
                      s"""{"error":"Invalid XML","details":${result.errors.mkString("[\"", "\",\"", "\"]")}}"""))
                }
              }
            },
            get {
              configStore.get(configName) match {
                case Some(xmlBody) =>
                  val result = ConfigXmlParser.parseConfigXml(xmlBody)
                  complete(HttpEntity(ContentTypes.`application/json`,
                    ConfigToJson.resultToJson(result)))
                case None =>
                  complete(StatusCodes.NotFound,
                    HttpEntity(ContentTypes.`application/json`,
                      s"""{"error":"Configuration '$configName' not found"}"""))
              }
            }
          )
        },
        path("validate") {
          post {
            entity(as[String]) { xmlBody =>
              val result = ConfigXmlParser.parseConfigXml(xmlBody)
              val isValid = result.errors.isEmpty
              val json =
                s"""{"valid":$isValid,"settingsCount":${result.settings.size},"errors":${result.errors.map(e => s""""$e"""").mkString("[", ",", "]")}}"""
              if (isValid) {
                complete(HttpEntity(ContentTypes.`application/json`, json))
              } else {
                complete(StatusCodes.BadRequest,
                  HttpEntity(ContentTypes.`application/json`, json))
              }
            }
          }
        },
        path("merge") {
          post {
            entity(as[String]) { body =>
              // Expect JSON-like body with two XML configs to merge
              // For simplicity, accept two XML documents separated by a delimiter
              val parts = body.split("---MERGE_DELIMITER---")
              if (parts.length == 2) {
                val result1 = ConfigXmlParser.parseConfigXml(parts(0).trim)
                val result2 = ConfigXmlParser.parseConfigXml(parts(1).trim)

                if (result1.errors.isEmpty && result2.errors.isEmpty) {
                  val mergedMap = mutable.LinkedHashMap[String, ConfigSetting]()
                  result1.settings.foreach(s => mergedMap(s.key) = s)
                  result2.settings.foreach(s => mergedMap(s.key) = s) // second overrides first

                  val merged = ConfigParseResult(mergedMap.values.toList, List.empty)
                  complete(HttpEntity(ContentTypes.`application/json`,
                    ConfigToJson.resultToJson(merged)))
                } else {
                  val allErrors = result1.errors ++ result2.errors
                  complete(StatusCodes.BadRequest,
                    HttpEntity(ContentTypes.`application/json`,
                      s"""{"error":"Parse errors in input","details":${allErrors.map(e => s""""$e"""").mkString("[", ",", "]")}}"""))
                }
              } else {
                complete(StatusCodes.BadRequest,
                  HttpEntity(ContentTypes.`application/json`,
                    """{"error":"Expected two XML documents separated by ---MERGE_DELIMITER---"}"""))
              }
            }
          }
        }
      )
    }

  val bindingFuture: Future[Http.ServerBinding] =
    Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      println(s"Configuration Management Service running at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
    case Failure(exception) =>
      println(s"Failed to start server: ${exception.getMessage}")
      system.terminate()
  }
}